export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;
export type ScenarioResult = { results: StepResult[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const baseFor = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

const quote = (step: QuoteStep): QuoteResult => {
  const itemTotal = step.items.reduce(
    (sum, item) => sum + baseFor(item) * (1 + FIRST_INSURANCE_RATE),
    0,
  );
  return { premium: Math.ceil(itemTotal) + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return { results: scenario.steps.map(quote) };
};

