  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: dragon attack with two sword damage entries → each treated separately with own deductible");
  it.todo("damages contain more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (modifiers do not raise cap)");
  it.todo("policy with sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured (cap 2000 G); two successive 1500 G claims → first 1400 G remaining 600 G; second 600 G remaining 0 G");

