import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per main item type (no modifiers, 0 years, first quote) ---
  // Plain item base premium + 10 G first-insurance + 5 G fee
  it("plain sword (steel, enchantment 0) for new customer → premium 115 G (100 + 10 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("plain amulet for new customer → premium 71 G (60 + 6 first-insurance rounded up + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("plain staff for new customer → premium 93 G (80 + 8 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 93 }] });
  });
  it("plain potion for new customer → premium 49 G (40 + 4 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Component pricing (runes/moonstones) ---
  it("2 runes → premium 60 G (50 base + 5 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → premium 71 G (60 block + 6 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → premium 115 G (no block; 100 base + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → premium 198 G (no block: 7*25=175 base + 17.5 first-insurance rounded up + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 198 }] });
  });

  // --- 'Alike' components clarification (❓) ---
  it("2 runes + 1 moonstone → premium 88 G (no block: 75 base + first-insurance + fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → premium 137 G (two blocks: 120 + 12 first-ins + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Modifiers in isolation (item-specific) ---
  it("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (130 G + 5 fee + 13 first ins.)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
  it.todo("first quote in scenario carries 10% first-insurance surcharge per item");
  it.todo("second quote in scenario gets 15% follow-up contract discount");

  // --- Modifier scope on multi-item policies (❓) ---
  it.todo("cursed sword + plain amulet → 210 G before fee (item-specific surcharge applies only to cursed item)");

  // --- Rounding in MHPCO's favor ---
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
  it.todo("intermediate amounts kept as fractions; only final is rounded");

  // --- Integration examples ---
  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7) → premium 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");

  // --- Claim processing: enchantment threshold ---
  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon only: full minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per damaged item)");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: dragon attack with two sword damage entries → each treated separately with own deductible");
  it.todo("damages contain more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (modifiers do not raise cap)");
  it.todo("policy with sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured (cap 2000 G); two successive 1500 G claims → first 1400 G remaining 600 G; second 600 G remaining 0 G");

  // --- Edge cases ---
  it.todo("quote includes unknown item type (e.g. 'broomstick') → CLI exits non-zero with stderr error, no results on stdout");
  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr error");
  it.todo("claim references damage entry with unknown item type → CLI exits non-zero with stderr error");
  it.todo("claim contains damage entry with negative amount → CLI exits non-zero with stderr error");

  // --- End-to-end schema example ---
  it.todo("schema example: long-standing customer amulet quote + fire claim 200 G → premium and payout integers per schema");
});

