export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;
export type ScenarioResult = { results: StepResult[] };

const PROCESSING_FEE = 5;
// Premiums are accumulated in tenths of a gold piece so we can apply
// fractional surcharges/discounts with integer math and round once at the end
// (avoids floating-point artifacts like 100 * 1.1 = 110.00000000000001).
const TENTHS_PER_UNIT = 10;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremium(item), 0);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const groupByType = (items: Item[]): Item[][] => {
  const groups: Record<string, Item[]> = {};
  for (const item of items) {
    (groups[item.type] ??= []).push(item);
  }
  return Object.values(groups);
};

const componentGroupBasePremium = (group: Item[]): number =>
  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mains = items.filter((item) => !isComponent(item));
  const componentTotal = groupByType(components)
    .map(componentGroupBasePremium)
    .reduce((sum, premium) => sum + premium, 0);
  return sumBasePremiums(mains) + componentTotal;
};

const roundUpTenthsToUnits = (tenths: number): number => Math.ceil(tenths / TENTHS_PER_UNIT);

// Modifiers are expressed as +N tenths per gold of base premium (additive).
// Item-specific modifiers attach to a single item's base premium.
// Policy-wide modifiers attach to the total base premium of the policy.
const CURSE_SURCHARGE_TENTHS = 5; // +50% on a cursed item
const HIGH_ENCHANTMENT_SURCHARGE_TENTHS = 3; // +30% when enchantment >= 5
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_QUOTE_SURCHARGE_TENTHS = 1; // +10% on the whole policy
const LOYALTY_DISCOUNT_TENTHS = 2; // -20% when customer >= 2 years
const LOYALTY_THRESHOLD_YEARS = 2;

const itemModifierTenthsPerGold = (item: Item): number => {
  let tenths = 0;
  if (item.cursed) tenths += CURSE_SURCHARGE_TENTHS;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
    tenths += HIGH_ENCHANTMENT_SURCHARGE_TENTHS;
  return tenths;
};

const itemSurchargeTenths = (item: Item): number =>
  basePremium(item) * itemModifierTenthsPerGold(item);

const sumItemSurchargesTenths = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargeTenths(item), 0);

type Customer = { yearsWithMHPCO: number };

const policyModifierTenthsPerGold = (customer: Customer): number => {
  let tenths = FIRST_QUOTE_SURCHARGE_TENTHS;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) tenths -= LOYALTY_DISCOUNT_TENTHS;
  return tenths;
};

const quote = (step: QuoteStep, customer: Customer): QuoteResult => {
  const baseGold = itemsBasePremium(step.items);
  const baseTenths = baseGold * TENTHS_PER_UNIT;
  const itemSurcharges = sumItemSurchargesTenths(step.items);
  const policyAdj = baseGold * policyModifierTenthsPerGold(customer);
  const totalTenths = baseTenths + itemSurcharges + policyAdj;
  return { premium: roundUpTenthsToUnits(totalTenths) + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return { results: scenario.steps.map((step) => quote(step, scenario.customer)) };
};

