import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per main item type (no modifiers, 0 years, first quote) ---
  // Plain item base premium + 10 G first-insurance + 5 G fee
  it("plain sword (steel, enchantment 0) for new customer → premium 115 G (100 + 10 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("plain amulet for new customer → premium 71 G (60 + 6 first-insurance rounded up + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("plain staff for new customer → premium 93 G (80 + 8 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 93 }] });
  });
  it("plain potion for new customer → premium 49 G (40 + 4 + 5)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Component pricing (runes/moonstones) ---
  it("2 runes → premium 60 G (50 base + 5 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → premium 71 G (60 block + 6 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → premium 115 G (no block; 100 base + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → premium 198 G (no block: 7*25=175 base + 17.5 first-insurance rounded up + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 198 }] });
  });

  // --- 'Alike' components clarification (❓) ---
  it("2 runes + 1 moonstone → premium 88 G (no block: 75 base + first-insurance + fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → premium 137 G (two blocks: 120 + 12 first-ins + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Modifiers in isolation (item-specific) ---
  it("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with exactly enchantment 5 → premium 145 G (100 + 30 high-ench + 10 first-ins + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge (premium 115 G)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with exactly enchantment 5 → premium 195 G (100 + 50 curse + 30 ench + 10 first-ins + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 195 }] });
  });

  // --- Policy-wide modifiers ---
  it("customer with exactly 2 years with MHPCO → loyalty discount applies (plain sword → 95 G)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 95 }] });
  });
  it("second quote in scenario gets 15% follow-up contract discount (plain sword, 0 years, 2nd quote → 100 base + 10 first-ins - 15 follow-up + 5 fee = 100)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
  });

  // --- Modifier scope on multi-item policies (❓) ---
  it("cursed sword + plain amulet → premium 231 G (160 base + 50 curse + 16 first-ins + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(out).toEqual({ results: [{ premium: 231 }] });
  });

  // --- Rounding in MHPCO's favor ---
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
  it.todo("intermediate amounts kept as fractions; only final is rounded");

  // --- Integration examples ---
  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7) → premium 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");

  // --- Claim processing: enchantment threshold ---
  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon only: full minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per damaged item)");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: dragon attack with two sword damage entries → each treated separately with own deductible");
  it.todo("damages contain more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (modifiers do not raise cap)");
  it.todo("policy with sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured (cap 2000 G); two successive 1500 G claims → first 1400 G remaining 600 G; second 600 G remaining 0 G");

  // --- Edge cases ---
  it.todo("quote includes unknown item type (e.g. 'broomstick') → CLI exits non-zero with stderr error, no results on stdout");
  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr error");
  it.todo("claim references damage entry with unknown item type → CLI exits non-zero with stderr error");
  it.todo("claim contains damage entry with negative amount → CLI exits non-zero with stderr error");

  // --- End-to-end schema example ---
  it.todo("schema example: long-standing customer amulet quote + fire claim 200 G → premium and payout integers per schema");
});

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;
export type ScenarioResult = { results: StepResult[] };

const PROCESSING_FEE = 5;
// Premiums are accumulated in hundredths of a gold piece so we can apply
// percentage surcharges/discounts (10%, 15%, 20%, 30%, 50%) with integer math
// and round once at the end (avoids floating-point artifacts).
const HUNDREDTHS_PER_UNIT = 100;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremium(item), 0);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const groupByType = (items: Item[]): Item[][] => {
  const groups: Record<string, Item[]> = {};
  for (const item of items) {
    (groups[item.type] ??= []).push(item);
  }
  return Object.values(groups);
};

const componentGroupBasePremium = (group: Item[]): number =>
  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mains = items.filter((item) => !isComponent(item));
  const componentTotal = groupByType(components)
    .map(componentGroupBasePremium)
    .reduce((sum, premium) => sum + premium, 0);
  return sumBasePremiums(mains) + componentTotal;
};

const roundUpHundredthsToUnits = (h: number): number => Math.ceil(h / HUNDREDTHS_PER_UNIT);

// Modifier rates are expressed in hundredths-per-gold of base premium (i.e. percentage points).
// Item-specific modifiers attach to a single item's base premium.
// Policy-wide modifiers attach to the total base premium of the policy.
const CURSE_SURCHARGE = 50;
const HIGH_ENCHANTMENT_SURCHARGE = 30;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_QUOTE_SURCHARGE = 10;
const LOYALTY_DISCOUNT = 20;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOWUP_DISCOUNT = 15;

const itemModifierRate = (item: Item): number => {
  let rate = 0;
  if (item.cursed) rate += CURSE_SURCHARGE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
  return rate;
};

const itemSurchargeHundredths = (item: Item): number => basePremium(item) * itemModifierRate(item);

const sumItemSurchargesHundredths = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargeHundredths(item), 0);

type Customer = { yearsWithMHPCO: number };

const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
  let rate = FIRST_QUOTE_SURCHARGE;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
  if (quoteIndex > 0) rate -= FOLLOWUP_DISCOUNT;
  return rate;
};

const quote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
  const baseGold = itemsBasePremium(step.items);
  const baseHundredths = baseGold * HUNDREDTHS_PER_UNIT;
  const itemSurcharges = sumItemSurchargesHundredths(step.items);
  const policyAdj = baseGold * policyModifierRate(customer, quoteIndex);
  const totalHundredths = baseHundredths + itemSurcharges + policyAdj;
  return { premium: roundUpHundredthsToUnits(totalHundredths) + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteIndex = 0;
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push(quote(step, scenario.customer, quoteIndex));
      quoteIndex += 1;
    }
  }
  return { results };
};

