const countBy = <T>(items: T[], key: (item: T) => string): Record<string, number> =>
  items.reduce<Record<string, number>>((acc, item) => {
    const k = key(item);
    acc[k] = (acc[k] ?? 0) + 1;
    return acc;
  }, {});

const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
  const insuredCounts = countBy(policy.items, (item) => item.type);
  const damageCounts = countBy(damages, (damage) => damage.itemType);
  for (const [itemType, dCount] of Object.entries(damageCounts)) {
    if (dCount > (insuredCounts[itemType] ?? 0)) {
      throw new Error(`claim has ${dCount} damages of type "${itemType}" but policy covers only ${insuredCounts[itemType] ?? 0}`);
    }
  }
};

